export function buildSubmenuCss(n,e,o){const a=o&&"none"===e?"20rem":e;return`/* ── Hamburger: visível só no mobile ───────────────────────────── */\n.fwku-hamburger-btn {\n  display: block;\n}\n@media (min-width: ${n}px) {\n  .fwku-hamburger-btn {\n    display: none !important;\n  }\n}\n/* ── Submenu container ─────────────────────────────────────────── */\n.fwku-menu-submenu {\n  position: relative;\n}\n\n/* ── Caret: primeiro nível (aponta para baixo) ──────────────────── */\n.fwku-navbar-nav > .fwku-menu-submenu > .fwku-menu-toggle::after {\n  display: inline-block;\n  margin-left: 0.355em;\n  vertical-align: 0.155em;\n  content: "";\n  border-top: 0.3em solid;\n  border-right: 0.3em solid transparent;\n  border-bottom: 0;\n  border-left: 0.3em solid transparent;\n  transition: transform 0.25s ease;\n}\n\n/* ── Caret: submenus aninhados (aponta para a direita) ──────────── */\n.fwku-menu-dropdown .fwku-menu-submenu > .fwku-menu-toggle::after {\n  display: inline-block;\n  margin-left: 0.355em;\n  vertical-align: 0.155em;\n  content: "";\n  border-top: 0.3em solid transparent;\n  border-right: 0;\n  border-bottom: 0.3em solid transparent;\n  border-left: 0.3em solid;\n  position: absolute;\n  right: 1rem;\n  top: 0.95em;\n  transition: transform 0.25s ease;\n}\n\n/* ── Dropdown panel ─────────────────────────────────────────────── */\n.fwku-menu-dropdown {\n  display: none;\n  position: absolute;\n  z-index: 1000;\n  min-width: 12rem;\n  max-width: ${a};\n  padding: 0.5rem 0;\n  margin: 0;\n  font-size: 1rem;\n  color: var(--fwku-menu-text, inherit);\n  background-color: var(--fwku-menu-bg, #fff);\n  border: 1px solid var(--fwku-menu-border, rgba(0,0,0,.15));\n  border-radius: var(--fwku-menu-radius, 0.375rem);\n  box-shadow: 0 0.5rem 1rem rgba(0,0,0,.175);\n  list-style: none;\n}\n\n.fwku-menu-dropdown.fwku-show {\n  display: block;\n}\n\n/* ── Primeiro nível: cai PARA BAIXO sob o item do nav ──────────── */\n.fwku-navbar-nav > .fwku-menu-submenu > .fwku-menu-dropdown {\n  top: 100%;\n  left: 0;\n  margin-top: -1px; /* sobrepõe 1px o li para não haver lacuna sob o mouse */\n}\n\n/* Primeiro nível: quando não há espaço à direita, alinha pela direita do parent */\n.fwku-navbar-nav > .fwku-menu-submenu > .fwku-menu-dropdown.left-aligned {\n  left: auto !important;\n  right: 0 !important;\n}\n\n/* ── Submenus aninhados: abre para a DIREITA ────────────────────── */\n.fwku-menu-dropdown .fwku-menu-submenu > .fwku-menu-dropdown {\n  top: 0;\n  left: 100%;\n  margin-top: -6px;\n  margin-left: -1px; /* sobrepõe 1px o pai para não haver lacuna lateral */\n}\n\n/* Submenus aninhados: quando não há espaço à direita, abre para a ESQUERDA */\n.fwku-menu-dropdown .fwku-menu-submenu > .fwku-menu-dropdown.left-aligned {\n  left: auto !important;\n  right: 100% !important;\n  margin-left: 0;\n  margin-right: -1px; /* mesmo overlap no lado esquerdo */\n}\n\n/* ── Hover no desktop (primeiro nível e nested) ───────────────── */\n@media (min-width: ${n}px) {\n  .fwku-navbar-nav > .fwku-menu-submenu:hover > .fwku-menu-dropdown,\n  .fwku-menu-dropdown .fwku-menu-submenu:hover > .fwku-menu-dropdown {\n    display: block;\n  }\n}\n\n/* ── Itens DENTRO do dropdown (não sobrescrevem nav-link do topo) ─ */\n/* Especificidade 0-3-0: garante precedência sobre regras do Bootstrap (0-2-0). */\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-item,\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-link,\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-toggle {\n  display: block;\n  width: 100%;\n  padding: 0.35rem 1rem;\n  clear: both;\n  font-weight: 400;\n  color: var(--fwku-menu-item-color, inherit);\n  text-align: inherit;\n  text-decoration: none;\n  white-space: nowrap;\n  background-color: transparent;\n  border: 0;\n  cursor: pointer;\n  box-sizing: border-box;${o?`\n  overflow: hidden;\n  text-overflow: ellipsis;\n  max-width: ${a};`:""}\n}\n\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-toggle {\n  position: relative;\n  padding-right: 2rem;\n}\n\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-item:hover,\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-link:hover,\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-toggle:hover {\n  background-color: var(--fwku-menu-item-hover-bg, rgba(0,0,0,.05));\n  color: var(--fwku-menu-item-hover-color, inherit);\n}\n\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-item:focus,\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-link:focus,\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-toggle:focus {\n  outline: 2px solid var(--fwku-menu-focus-outline, var(--bs-primary, #0d6efd));\n  outline-offset: 2px;\n  background-color: var(--fwku-menu-focus-bg, #f8f9fa);\n}\n\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-item:focus-visible,\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-link:focus-visible,\n.fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-toggle:focus-visible {\n  outline: 2px solid var(--fwku-menu-focus-outline, var(--bs-primary, #0d6efd));\n  outline-offset: 2px;\n}\n\n@media (prefers-contrast: high) {\n  .fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-item:focus,\n  .fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-link:focus,\n  .fwku-menu-submenu .fwku-menu-dropdown .fwku-menu-toggle:focus {\n    outline: 3px solid currentColor;\n  }\n}\n\n/* ── Fixed navbar ───────────────────────────────────────────────── */\n.fwku-fixed {\n  position: fixed;\n  top: 0;\n  right: 0;\n  left: 0;\n  z-index: 1030;\n}\n\n/* ── Mobile ─────────────────────────────────────────────────────── */\n@media (max-width: ${n-1}px) {\n  .fwku-menu-submenu .fwku-menu-dropdown {\n    position: static;\n    left: 0;\n    right: auto;\n    top: auto;\n    margin: 0;\n    padding-left: 1rem;\n    box-shadow: none;\n    border: none;\n    border-left: 2px solid var(--fwku-menu-border, rgba(0,0,0,.1));\n    border-radius: 0;\n    /* Acordeão animado — sem dependências, pura CSS transition */\n    display: block !important;\n    max-height: 0;\n    overflow: hidden;\n    opacity: 0;\n    transition: max-height 0.32s ease-out, opacity 0.22s ease;\n  }\n  .fwku-menu-submenu .fwku-menu-dropdown.fwku-show {\n    /* Altura exacta definida por JS via --fwku-sub-height */\n    max-height: var(--fwku-sub-height, 600px);\n    opacity: 1;\n    transition: max-height 0.35s ease-in, opacity 0.2s ease 0.05s;\n  }\n  .fwku-navbar-nav > .fwku-menu-submenu > .fwku-menu-dropdown {\n    margin-top: 0;\n    width: 100%;\n  }\n  /* Caret: rotaciona 180° quando o acordeão está aberto */\n  .fwku-menu-submenu.fwku-open > .fwku-menu-toggle::after {\n    transform: rotate(180deg);\n  }\n  /* Aninhados: caret aponta para baixo quando aberto (não mais para a direita) */\n  .fwku-menu-dropdown .fwku-menu-submenu.fwku-open > .fwku-menu-toggle::after {\n    transform: rotate(90deg);\n  }\n  /* Respeita preferência do sistema por menos movimento */\n  @media (prefers-reduced-motion: reduce) {\n    .fwku-menu-submenu .fwku-menu-dropdown {\n      transition: none !important;\n    }\n  }\n}\n\n/* ── Mobile nav collapse ─────────────────────────────────────────── */\n.fwku-menu-collapse {\n  display: none;\n  width: 100%;\n}\n\n/* Mobile: expande em coluna, itens ocupam toda a largura */\n.fwku-menu-collapse.fwku-show {\n  display: flex !important;\n  flex-direction: column;\n  align-items: stretch !important;\n  flex-basis: auto !important;\n  flex-grow: 1;\n  flex-wrap: nowrap;\n}\n\n/* Desktop: linha horizontal */\n@media (min-width: ${n}px) {\n  .fwku-menu-collapse,\n  .fwku-menu-collapse.fwku-show {\n    display: flex !important;\n    flex-direction: row !important;\n    align-items: center !important;\n    flex-basis: auto !important;\n    flex-grow: 1;\n    flex-wrap: nowrap;\n  }\n}\n\n/* ── @keyframes — disponíveis em todos os breakpoints ───────────────── */\n\n/* 1. fade-slide */\n@keyframes fwku-anim-fade-slide-down {\n  from { opacity: 0; transform: translateY(-10px); }\n  to   { opacity: 1; transform: translateY(0); }\n}\n@keyframes fwku-anim-fade-slide-right {\n  from { opacity: 0; transform: translateX(-8px); }\n  to   { opacity: 1; transform: translateX(0); }\n}\n\n/* 2. scale */\n@keyframes fwku-anim-scale {\n  from { opacity: 0.6; transform: scaleY(0.5); }\n  to   { opacity: 1;   transform: scaleY(1); }\n}\n\n/* 3. flip */\n@keyframes fwku-anim-flip {\n  from { opacity: 0; transform: perspective(600px) rotateX(-22deg); }\n  to   { opacity: 1; transform: perspective(600px) rotateX(0deg); }\n}\n\n/* 4. spring */\n@keyframes fwku-anim-spring {\n  0%   { opacity: 0; transform: translateY(-12px) scaleY(0.88); }\n  55%  { opacity: 1; transform: translateY(3px)   scaleY(1.03); }\n  78%  { transform: translateY(-1px) scaleY(0.99); }\n  100% { opacity: 1; transform: translateY(0)     scaleY(1); }\n}\n\n/* 5. reveal — scaleY/scaleX: sem clip-path, sem transpariência na área animada */\n@keyframes fwku-anim-reveal-down {\n  from { transform: scaleY(0); }\n  to   { transform: scaleY(1); }\n}\n@keyframes fwku-anim-reveal-right {\n  from { transform: scaleX(0); }\n  to   { transform: scaleX(1); }\n}\n\n/* ── Animações de abertura — desktop (aplica no painel dropdown) ─── */\n@media (min-width: ${n}px) {\n\n  /* fade-slide: primeiro nível desce; aninhados vêm da esquerda */\n  [data-fwku-menu-conf-animation="fade-slide"]\n    .fwku-navbar-nav > .fwku-menu-submenu > .fwku-menu-dropdown.fwku-show {\n    animation: fwku-anim-fade-slide-down 0.18s ease forwards;\n  }\n  [data-fwku-menu-conf-animation="fade-slide"]\n    .fwku-menu-dropdown .fwku-menu-submenu > .fwku-menu-dropdown.fwku-show {\n    animation: fwku-anim-fade-slide-right 0.15s ease forwards;\n  }\n\n  /* scale: desdobra scaleY a partir da borda superior */\n  [data-fwku-menu-conf-animation="scale"] .fwku-menu-dropdown.fwku-show {\n    animation: fwku-anim-scale 0.18s cubic-bezier(0.4, 0, 0.2, 1) forwards;\n    transform-origin: top left;\n  }\n\n  /* flip: vira em perspectiva 3D */\n  [data-fwku-menu-conf-animation="flip"] .fwku-menu-dropdown.fwku-show {\n    animation: fwku-anim-flip 0.22s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;\n    transform-origin: top center;\n    backface-visibility: hidden;\n  }\n\n  /* spring: bounce elástico com overshoot */\n  [data-fwku-menu-conf-animation="spring"] .fwku-menu-dropdown.fwku-show {\n    animation: fwku-anim-spring 0.4s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;\n    transform-origin: top left;\n  }\n\n  /* reveal: wipe direcional por scale (sem clip-path, sem artefatos de z-index) */\n  [data-fwku-menu-conf-animation="reveal"]\n    .fwku-navbar-nav > .fwku-menu-submenu > .fwku-menu-dropdown.fwku-show {\n    animation: fwku-anim-reveal-down 0.22s cubic-bezier(0.4, 0, 0.2, 1) forwards;\n    transform-origin: top left;\n  }\n  [data-fwku-menu-conf-animation="reveal"]\n    .fwku-menu-dropdown .fwku-menu-submenu > .fwku-menu-dropdown.fwku-show {\n    animation: fwku-anim-reveal-right 0.18s cubic-bezier(0.4, 0, 0.2, 1) forwards;\n    transform-origin: left top;\n  }\n}\n\n/* ── Animações de abertura — mobile (aplica nos itens > li) ──────── */\n/* O container abre via max-height+opacity (transition já definida).  */\n/* Os itens filhos recebem o efeito visual do modo selecionado.       */\n@media (max-width: ${n-1}px) {\n\n  [data-fwku-menu-conf-animation="fade-slide"]\n    .fwku-menu-dropdown.fwku-show > li {\n    animation: fwku-anim-fade-slide-down 0.22s ease both;\n  }\n\n  [data-fwku-menu-conf-animation="scale"]\n    .fwku-menu-dropdown.fwku-show > li {\n    animation: fwku-anim-scale 0.2s cubic-bezier(0.4, 0, 0.2, 1) both;\n    transform-origin: top left;\n  }\n\n  [data-fwku-menu-conf-animation="flip"]\n    .fwku-menu-dropdown.fwku-show > li {\n    animation: fwku-anim-flip 0.22s ease both;\n    transform-origin: top center;\n    backface-visibility: hidden;\n  }\n\n  [data-fwku-menu-conf-animation="spring"]\n    .fwku-menu-dropdown.fwku-show > li {\n    animation: fwku-anim-spring 0.4s cubic-bezier(0.34, 1.56, 0.64, 1) both;\n    transform-origin: top left;\n  }\n\n  [data-fwku-menu-conf-animation="reveal"]\n    .fwku-menu-dropdown.fwku-show > li {\n    animation: fwku-anim-reveal-down 0.2s cubic-bezier(0.4, 0, 0.2, 1) both;\n    transform-origin: top left;\n  }\n}\n\n/* Respeita preferência do sistema por menos movimento — desktop e mobile */\n@media (prefers-reduced-motion: reduce) {\n  [data-fwku-menu-conf-animation] .fwku-menu-dropdown.fwku-show,\n  [data-fwku-menu-conf-animation] .fwku-menu-dropdown.fwku-show > li {\n    animation: none !important;\n    transition-duration: 0.01ms !important;\n  }\n}\n`}